// === Validate & Sanitize Input (+ IP/Quota-Key) ===
const input   = $input.first().json;
const body    = input.body ?? input;
const headers = input.headers ?? {};

const ingredients = body.ingredients;
const prefs = body.preferences ?? {};

// --- Validation ---
if (!Array.isArray(ingredients) || ingredients.length < 1) {
  throw new Error('VALIDATION: At least one ingredient is required.');
}
const servings = Number(prefs.servings);
if (!Number.isInteger(servings) || servings < 1 || servings > 12) {
  throw new Error('VALIDATION: servings must be an integer between 1 and 12.');
}
const helpers = Number(prefs.helpers ?? 1);
if (!Number.isInteger(helpers) || helpers < 1 || helpers > 3) {
  throw new Error('VALIDATION: helpers must be an integer between 1 and 3.');
}

// --- Sanitizing ---
const clean = (s) => String(s ?? '').replace(/[<>]/g, '').trim().slice(0, 200);
const cleanIngredients = ingredients
  .map(i => ({ name: clean(i.name), amount: Number(i.amount) || 0, unit: clean(i.unit) }))
  .filter(i => i.name.length > 0);
if (cleanIngredients.length < 1) {
  throw new Error('VALIDATION: At least one valid ingredient with a name is required.');
}

const allowedStyles = ['german','italian','japanese','indian','gourmet','fusion'];
const allowedTimes  = ['quick','medium','elaborate'];
const cookingStyle = allowedStyles.includes(prefs.cookingStyle) ? prefs.cookingStyle : 'fusion';
const cookingTime  = allowedTimes.includes(prefs.cookingTime)   ? prefs.cookingTime  : 'medium';
const diet = clean(prefs.diet || 'none');

// --- Derive IP server-side from headers (NOT from client) ---
const xff = (headers['x-forwarded-for'] || headers['X-Forwarded-For'] || '').toString();
const rawIp = (xff.split(',')[0] || '').trim()
  || headers['x-real-ip']
  || '::1';

// djb2 inline hash -> short key, does not store IP in plaintext
function shortHash(str) {
  let h = 5381;
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) + h) + str.charCodeAt(i);
    h = h & 0xffffffff;
  }
  return (h >>> 0).toString(16);
}
const ipHash  = shortHash(String(rawIp));
const dateKey = new Date().toISOString().slice(0, 10); // YYYY-MM-DD

// --- Build user prompt ---
const userPrompt = [
  'Available ingredients:',
  ...cleanIngredients.map(i => `- ${i.name}: ${i.amount} ${i.unit}`.trim()),
  '',
  'Preferences:',
  `- Servings: ${servings}`,
  `- Cooking time preference: ${cookingTime}`,
  `- Cuisine style: ${cookingStyle}`,
  `- Dietary preference: ${diet}`,
  `- Number of helpers: ${helpers}`,
  '',
  'Generate exactly 3 recipes following the rules and JSON format.'
].join('\n');

const systemPrompt = `You are a professional chef and nutritionist.
You generate exactly 3 different recipe suggestions
based on the given ingredients and preferences.

RULES:
- Each recipe uses at least 70% of the listed ingredients
- Maximum 3 additional basic ingredients per recipe (spices, salt, oil, herbs, etc.)
- The 3 suggestions differ in preparation method
- All quantities are for the specified number of servings
- ingredients: ALL recipe ingredients with amount and unit (user-provided + extras)
- missingIngredients: ONLY the names of extra ingredients NOT from the user list (max 3)
- Every name in missingIngredients MUST also exist in ingredients with amount and unit
- Never list user-provided ingredients in missingIngredients
- Cooking steps in chronological order, mark parallel steps
- Nutritional values are realistic estimates

RESPONSE FORMAT: Valid JSON only, no Markdown code blocks:
{
  "recipes": [
    {
      "title": "string",
      "cookingStyle": "german|italian|japanese|indian|gourmet|fusion",
      "cookingTime": "quick|medium|elaborate",
      "cookingTimeMinutes": number,
      "servings": number,
      "ingredients": [{"name":"string","amount":number,"unit":"string"}],
      "missingIngredients": ["string"],
      "steps": [
        {
          "stepNumber": number,
          "description": "string",
          "durationMinutes": number,
          "isParallel": boolean,
          "parallelWith": [number]
        }
      ],
      "nutrition": {
        "caloriesPerPortion": number,
        "proteinG": number,
        "carbsG": number,
        "fatG": number
      },
      "helpers": [[{"helperIndex":0,"stepNumber":number,"description":"string"}]]
    }
  ]
}

IMPORTANT: You MUST always respond with valid JSON only. Never write plain text.
If you cannot generate recipes for any reason (inappropriate ingredients, ethical concerns, safety issues), respond with exactly:
{"error": "content_refused", "reason": "brief explanation in English"}`;

return [{
  json: {
    ingredients: cleanIngredients,
    preferences: { servings, cookingTime, cookingStyle, diet, helpers },
    meta: { ipHash, dateKey, timestamp: new Date().toISOString() },
    system: systemPrompt,
    userPrompt,
  },
}];

// === Evaluate Quota ===
let day = $input.first().json;
if (day && day.data !== undefined && day.body === undefined) day = day.data;
const data = (day && typeof day === 'object') ? day : {};

const meta = $('Validate & Sanitize Input').first().json.meta;
const ipHash  = meta.ipHash;
const dateKey = meta.dateKey;

const IP_LIMIT     = 3;
const SYSTEM_LIMIT = 12;

const ipCount     = Number(data[ipHash] || 0);
const systemCount = Number(data['_system'] || 0);
const allowed = ipCount < IP_LIMIT && systemCount < SYSTEM_LIMIT;

return [{
  json: { allowed, ipCount, systemCount, ipHash, dateKey, IP_LIMIT, SYSTEM_LIMIT }
}];

