// === Parse Claude Response ===
const res = $input.first().json;

if (res.error) {
  throw new Error('CLAUDE_API_ERROR: ' + (res.error.message || JSON.stringify(res.error)));
}
const textBlock = (res.content || []).find(b => b.type === 'text');
if (!textBlock || !textBlock.text) {
  throw new Error('PARSE: No text content in Claude response.');
}
let raw = textBlock.text.trim();
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error('PARSE: Claude did not return valid JSON. stop_reason=' +
    res.stop_reason + ' | first 200 chars: ' + raw.slice(0, 200));
}
const recipes = parsed.recipes;
if (parsed.error === 'content_refused') {
  throw new Error('CONTENT_REFUSED: ' + (parsed.reason || 'This ingredient cannot be used in recipes.'));
}
if (!Array.isArray(recipes) || recipes.length === 0) {
  throw new Error('PARSE: Expected a non-empty "recipes" array.');
}
recipes.forEach((r, idx) => {
  if (!r.title || !Array.isArray(r.ingredients) || !Array.isArray(r.steps)) {
    throw new Error(`PARSE: Recipe #${idx + 1} is missing required fields (title/ingredients/steps).`);
  }
});


const userIngredients = $('Validate & Sanitize Input').first().json.ingredients || [];

function normalizeName(name) {
  return String(name ?? '').toLowerCase().trim()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ');
}
function stemName(name) {
  return name.replace(/(chen|eln|en|n|e|s)$/, '');
}
function namesMatch(a, b) {
  const left = normalizeName(a);
  const right = normalizeName(b);
  if (!left || !right) return false;
  if (left === right) return true;
  if (stemName(left) === stemName(right)) return true;
  return left.includes(right) || right.includes(left);
}
function isUserIngredient(name) {
  return userIngredients.some((u) => namesMatch(u.name, name));
}

recipes.forEach((r) => {
  if (!Array.isArray(r.ingredients)) r.ingredients = [];
  const extraNames = r.ingredients
    .filter((ing) => !isUserIngredient(ing.name))
    .map((ing) => String(ing.name || '').trim())
    .filter(Boolean);
  r.missingIngredients = [...new Set(extraNames)].slice(0, 3);
});

return [{ json: { success: true, count: recipes.length, recipes, usage: res.usage ?? null } }];

